// `lift` is a fully generic combinator — no type annotations anywhere.
// GCP infers the complete type of `entity` BACKWARD through the chain:
//
//   sel    reads  entity.score  (Int field)
//   pred   expects an Int        (n >= 60)
//   → entity : { score: Int }
//
// TypeScript requires: <T, U, V>(sel: (e: T) => U) => (pred: (u: U) => V) => (e: T) => V
//   — THREE explicit generic parameters with arrow types
// Haskell:  lift sel pred = pred . sel  — fine but entity must be a DECLARED data type

let lift = sel -> pred -> entity -> pred(sel(entity));

let get_score  = player -> player.score;
let is_passing = n -> n >= 60;
let is_ace     = n -> n >= 90;

let check_pass = lift(get_score)(is_passing);
let check_ace  = lift(get_score)(is_ace);

check_pass({name = "Alice", score = 85, rank = 3});   // → true
check_ace( {name = "Alice", score = 95, rank = 1});   // → true (ace threshold)

// lift(sel)(pred)(entity) = pred(sel(entity))
// — a generic 3-level HOF with ZERO type annotations.
//
// GCP propagates constraints BACKWARD through the chain:
//   1. is_passing  needs  n.points    → sel result must have { points: Int }
//   2. get_score   returns player.test → player.test must have { points: Int }
//   3. alice.test = { score=85, gpa=3.5 } — no 'points' field!
//   → ERROR reported at check_pass(alice)
//
// No other type system catches this without EXPLICIT type annotations on lift.

let lift = sel -> pred -> entity -> pred(sel(entity));

let get_score  = player -> player.test;        // selects the 'test' sub-entity
let is_passing = n -> n.points >= 60;          // needs n.points : Int
let is_ace     = n -> n.score  >= 90;          // needs n.score  : Int

let check_pass = lift(get_score)(is_passing);
let check_ace  = lift(get_score)(is_ace);

// alice.test has { score, gpa } but NOT { points }
// → check_pass(alice) is a TYPE ERROR: 'points' field missing
let alice = {name = "Alice", test = {score = 85, gpa = 3.5}, rank = 3};

let pass = check_pass(alice);   // ← ERROR: points not found in alice.test
let ace  = check_ace(alice);    // ✓  score exists

(pass, ace)

// Outline entity templates support two kinds of auto-filled fields:
//
//   alias:  "guest"        → DEFAULT VALUE — String field with a preset default.
//                            Auto-fills if omitted, but CAN be overridden.
//
//   issuer: #"GCP-System"  → LITERAL TYPE  — the type IS the value.
//                            Always "GCP-System"; never assigned, never overridden.
//
// TypeScript: literal types are constraints only — you must still write the value.
// Haskell:    no direct equivalent without phantom types / Template Haskell.
// GCP:        both fill automatically at construction time.

outline ApiKey = {
    key:    String,
    alias:  "guest",          // default value — auto-fills as "guest", overridable
    access: String,
    issuer: #"GCP-System"    // literal type  — always "GCP-System", immutable
};

// Only required fields needed — alias and issuer fill automatically
let k1 = ApiKey{key = "abc123", access = "admin"};
// k1.alias   → "guest"        (default applied)
// k1.issuer  → "GCP-System"   (literal type filled)

// Override the default alias
let k2 = ApiKey{key = "xyz789", access = "read", alias = "alice"};
// k2.alias  → "alice"         (default overridden)

k1.issuer;   // → "GCP-System"

// TypeScript:  type ApiKey = { issuer: "GCP-System" }
//   → you MUST still write  { issuer: "GCP-System" }  in every object literal
//   → literal types are type CONSTRAINTS, not runtime values
//
// Haskell:  impossible without phantom types / singletons (highly verbose)
//
// GCP:  #"GCP-System" IS the value.
//   Any entity conforming to ApiKey gets `issuer` for FREE — never assigned.

outline AccessLevel = ReadOnly | ReadWrite | Admin;
outline ApiKey = {
    key:    String,
    access: AccessLevel,
    issuer: #"GCP-System"   // ← literal type — auto-fills, always "GCP-System"
};

let make_key = k -> lvl -> ApiKey{key = k, access = lvl};

let k1 = make_key("abc123")(Admin);
let k2 = make_key("xyz789")(ReadOnly);

// `issuer` was NEVER mentioned in make_key — yet it is guaranteed:
k1.issuer;   // → "GCP-System"

