// Neither function alone determines the full type.
// GCP merges their constraints: emp : { salary: Int, years: Int }
//
// TypeScript: (emp: { salary: number; years: number }) => ... — must declare
// Haskell:    data Emp = Emp { salary :: Int, years :: Int }  — must declare
//
// GCP: zero declarations — structural type emerges from usage.

let gross    = emp -> emp.salary * 12;   // constrains emp.salary : Int
let is_senior = emp -> emp.years >= 10;  // constrains emp.years  : Int

// Extra fields (name, dept) pass through — structural subtyping
let alice = {salary = 5000, years = 12, name = "Alice"};
let bob   = {salary = 4000, years = 5,  name = "Bob"};

let earn_alice = gross(alice);       // 60000
let earn_bob   = gross(bob);         // 48000
let senior     = is_senior(alice);   // true

earn_alice;

// `ticket` type is NEVER declared.
// GCP infers it from all access patterns across both functions:
//   urgency_of   reads  ticket.priority  → Priority (ADT)
//   urgency_of   reads  ticket.deadline  → Int
// → ticket : { priority: Priority, deadline: Int }
//
// In TypeScript: interface Ticket { priority: Priority; deadline: number }
// In Haskell:    data Ticket = Ticket { priority :: Priority, deadline :: Int }

outline Priority = Low | Medium | High;

let urgency_score = pri -> days ->
    match pri {
        High   -> 3 > days,
        Medium -> 7 > days,
        _      -> false
    };

let is_urgent = ticket -> urgency_score(ticket.priority)(ticket.deadline);

let t1 = {priority = High,   deadline = 2, owner = "Alice"};
let t2 = {priority = Medium, deadline = 10, owner = "Bob"};
let t3 = {priority = Low,    deadline = 1,  owner = "Carol"};

is_urgent(t1);   // → true   (High, 2 days left)

