p1.sku;   // → "AUTO"

// Entity literal type: a field whose type IS a specific entity constant.
// The constant is always auto-filled — callers cannot override it.
//
// Useful for embedding immutable configuration into a typed record.

outline Service = {
    name: String,
    meta: #{ env = "prod", version = 1 }   // entity literal — always this exact record
};

// Only `name` needs to be supplied — `meta` is auto-filled from the literal
let svc = Service{name = "auth-service"};

// Trying to override meta at construction is a compile-time error:
//   let bad = Service{name = "x", meta = {env = "dev", version = 2}};  // ← NOT_ASSIGNABLE

// Always the literal value regardless of construction arguments
svc.meta.env;   // → "prod"

// Tuple literal type: a field whose type IS a specific tuple constant.
// Works identically to string literal types — auto-filled, immutable.
//
// Practical use: embed a known coordinate, version pair, range, etc.

outline Origin = {
    label:  String,
    coords: #(0, 0)   // tuple literal — always (0, 0)
};

outline VersionedApi = {
    name:    String,
    version: #(1, 0, 0)   // semantic version — always 1.0.0
};

let o   = Origin{label = "centre"};
let api = VersionedApi{name = "gateway"};

// Trying to supply coords=(1,2) is a compile-time error (NOT_ASSIGNABLE)
// let bad = Origin{label = "p", coords = (1, 2)};

// Both fields are guaranteed by the type
(o.label, o.coords, api.version)

// External builders: __name__<OutlineType>{overrides}
//
// GCP checks the type at compile time — the outline type constrains what
// fields are valid.  At runtime, a registered plugin fills in the values.
//
// __external_builder__ is the built-in default: it constructs an entity
// from the supplied field overrides (same semantics as OutlineType{...}
// but the construction is delegated to the runtime layer).
//
// This lets the same GCP code work against different backends
// (memory, database, HTTP, etc.) by swapping only the registered plugin.

outline Profile = {
    id:     String,
    name:   String,
    role:   #"user"    // literal-type — always "user", auto-filled
};

// Construct via external builder with explicit field overrides.
// GCP infers: p : { id: String, name: String, role: String }
let p = __external_builder__<Profile>{id = "u001", name = "Alice"};

// Field access — type-safe, GCP inferred String for both
let pname = p.name;   // → "Alice"
let prole = p.role;   // → "user"  (literal type auto-filled)

(pname, prole)
